// Extract people array from Apollo API response
const contacts = $input.first().json.people;
return contacts.map(contact => ({ json: contact }));

// ============================================================
// Apollo.io URL → API JSON Body Converter
// Production-level | Drops unsupported params automatically
// ============================================================

const input = $input.first().json;
const apolloUrl = input.url;
const startPage = parseInt(input.start_page, 10) || 1;

// ─────────────────────────────────────────────
// STEP 1: Extract query string from Apollo URL
// ─────────────────────────────────────────────
let queryString = '';

if (apolloUrl.includes('#')) {
  const hashPart = apolloUrl.split('#')[1] || '';
  queryString = hashPart.includes('?') ? hashPart.split('?')[1] : '';
} else if (apolloUrl.includes('?')) {
  queryString = apolloUrl.split('?')[1];
}

if (!queryString) {
  throw new Error('No query parameters found in URL: ' + apolloUrl);
}

// ─────────────────────────────────────────────
// STEP 2: Parse all URL params into a map
// ─────────────────────────────────────────────
const params = {};

for (const part of queryString.split('&')) {
  if (!part) continue;
  const eqIndex = part.indexOf('=');
  if (eqIndex === -1) continue;
  const rawKey = part.substring(0, eqIndex);
  const rawVal = decodeURIComponent(part.substring(eqIndex + 1).replace(/\+/g, ' '));
  const key = rawKey.replace(/\[\]$/, '').replace(/\[/g, '[');
  if (!params[key]) params[key] = [];
  params[key].push(rawVal);
}

// ─────────────────────────────────────────────
// STEP 3: SUPPORTED API parameters map
// ─────────────────────────────────────────────
const SUPPORTED = {
  'personTitles':                          { key: 'person_titles',                           type: 'array' },
  'personNotTitles':                       { key: 'person_not_titles',                       type: 'array' },
  'personLocations':                       { key: 'person_locations',                        type: 'array' },
  'personSeniorities':                     { key: 'person_seniorities',                      type: 'array' },
  'organizationLocations':                 { key: 'organization_locations',                  type: 'array' },
  'organizationIds':                       { key: 'organization_ids',                        type: 'array' },
  'notOrganizationIds':                    { key: 'not_organization_ids',                    type: 'array' },
  'organizationNumEmployeesRanges':        { key: 'organization_num_employees_ranges',       type: 'array' },
  'organizationIndustryTagIds':            { key: 'organization_industry_tag_ids',           type: 'array' },
  'organizationNotIndustryTagIds':         { key: 'organization_not_industry_tag_ids',       type: 'array' },
  'contactEmailStatusV2':                  { key: 'contact_email_status',                    type: 'array' },
  'qOrganizationKeywordTags':              { key: 'q_organization_keyword_tags',             type: 'array' },
  'qNotOrganizationKeywordTags':           { key: 'q_not_organization_keyword_tags',         type: 'array' },
  'includedOrganizationKeywordFields':     { key: 'included_organization_keyword_fields',    type: 'array' },
  'excludedOrganizationKeywordFields':     { key: 'excluded_organization_keyword_fields',    type: 'array' },
  'qOrganizationDomainsList':              { key: 'q_organization_domains_list',             type: 'array' },
  'currentlyUsingAllOfTechnologyUids':     { key: 'currently_using_all_of_technology_uids',  type: 'array' },
  'currentlyUsingAnyOfTechnologyUids':     { key: 'currently_using_any_of_technology_uids',  type: 'array' },
  'currentlyNotUsingAnyOfTechnologyUids':  { key: 'currently_not_using_any_of_technology_uids', type: 'array' },
  'qOrganizationJobTitles':                { key: 'q_organization_job_titles',               type: 'array' },
  'organizationJobLocations':              { key: 'organization_job_locations',              type: 'array' },
  'existFields':                           { key: 'exist_fields',                            type: 'array' },
  'marketSegments':                        { key: 'market_segments',                         type: 'array' },
  'qPersonPersonaIds':                     { key: 'q_person_persona_ids',                    type: 'array' },
  'qKeywords':                             { key: 'q_keywords',                              type: 'string' },
  'qPersonTitle':                          { key: 'q_person_title',                          type: 'string' },
  'qOrganizationSearchListId':             { key: 'q_organization_search_list_id',           type: 'string' },
  'sortByField':                           { key: 'sort_by_field',                           type: 'string' },
  'sortAscending':                         { key: 'sort_ascending',                          type: 'boolean' },
  'includeSimilarTitles':                  { key: 'include_similar_titles',                  type: 'boolean' },
  'revenueRange[min]':                     { key: 'revenue_range',                           type: 'range_min' },
  'revenueRange[max]':                     { key: 'revenue_range',                           type: 'range_max' },
  'personTotalYoeRange[min]':              { key: 'person_total_yoe_range',                  type: 'range_min' },
  'personTotalYoeRange[max]':              { key: 'person_total_yoe_range',                  type: 'range_max' },
  'organizationNumJobsRange[min]':         { key: 'organization_num_jobs_range',             type: 'range_min' },
  'organizationNumJobsRange[max]':         { key: 'organization_num_jobs_range',             type: 'range_max' },
  'organizationJobPostedAtRange[min]':     { key: 'organization_job_posted_at_range',        type: 'range_min' },
  'organizationJobPostedAtRange[max]':     { key: 'organization_job_posted_at_range',        type: 'range_max' },
};

const UNSUPPORTED_DROP = new Set([
  'contactEmailStatus', 'organizationKeywordTags', 'personFunctions',
  'prospectedByCurrentTeam', 'isLikelyToEngage', 'emailStatus',
  'listId', 'tableView', 'viewMode', 'activeTab', 'page', 'perPage'
]);

// ─────────────────────────────────────────────
// STEP 4: Build the base filters (NO page)
// page is excluded here — loop controls it
// ─────────────────────────────────────────────
const baseFilters = {};
const dropped = [];
const rangeBuffer = {};

for (const [urlKey, values] of Object.entries(params)) {
  const match = SUPPORTED[urlKey];

  if (!match) {
    dropped.push({
      param: urlKey,
      reason: UNSUPPORTED_DROP.has(urlKey)
        ? 'UI-only filter, not supported by API'
        : 'Unknown parameter — not in API docs'
    });
    continue;
  }

  const { key, type } = match;

  if (type === 'array') {
    baseFilters[key] = values.map(v => v.trim()).filter(v => v !== '');
  } else if (type === 'string') {
    baseFilters[key] = values[0];
  } else if (type === 'boolean') {
    const val = values[0].toLowerCase();
    baseFilters[key] = val === 'true' || val === '1';
  } else if (type === 'range_min') {
    if (!rangeBuffer[key]) rangeBuffer[key] = {};
    rangeBuffer[key].min = isNaN(Number(values[0])) ? values[0] : Number(values[0]);
  } else if (type === 'range_max') {
    if (!rangeBuffer[key]) rangeBuffer[key] = {};
    rangeBuffer[key].max = isNaN(Number(values[0])) ? values[0] : Number(values[0]);
  }
}

for (const [rangeKey, rangeVal] of Object.entries(rangeBuffer)) {
  baseFilters[rangeKey] = rangeVal;
}

// Always set per_page
baseFilters.per_page = 100;

// ─────────────────────────────────────────────
// STEP 5: Output
// current_page is what the loop will use
// base_filters has everything EXCEPT page
// ─────────────────────────────────────────────
return [{
  json: {
    base_filters: baseFilters,
    current_page: startPage,
    total_pages: null,
    source_url: apolloUrl,
    dropped_params: dropped,
    total_dropped: dropped.length
  }
}];
